import request from "request";
import { parseStringPromise } from "xml2js";

// Import bookmarks from a remote XML feed. Legacy code path: it still uses the
// (deprecated) `request` library because it was written years ago and never
// migrated. `request` is the only thing pulling tough-cookie into the graph.
export function fetchXml(url) {
  return new Promise((resolve, reject) => {
    request({ url, method: "GET", jar: true }, (err, res, body) => {
      if (err) return reject(err);
      if (res.statusCode >= 400) {
        return reject(new Error(`upstream ${res.statusCode}`));
      }
      resolve(body);
    });
  });
}

export async function importBookmarks(xmlString) {
  const doc = await parseStringPromise(xmlString, { explicitArray: false });
  const items = doc?.bookmarks?.bookmark;
  if (!items) return [];
  const list = Array.isArray(items) ? items : [items];
  return list.map((b) => ({ title: b.title, url: b.url }));
}
import { test, before, after } from "node:test";
import assert from "node:assert/strict";
import http from "node:http";
import { fetchXml, importBookmarks } from "../src/importer.js";
import { createApp } from "../src/app.js";
import { listen } from "./helpers.js";

const SAMPLE = `<?xml version="1.0"?>
<bookmarks>
  <bookmark><title>Docs</title><url>https://docs.example.com</url></bookmark>
  <bookmark><title>Status</title><url>https://status.example.com</url></bookmark>
</bookmarks>`;

let origin;
let originBase;

before(async () => {
  origin = http.createServer((req, res) => {
    if (req.url === "/feed.xml") {
      res.setHeader("content-type", "application/xml");
      res.end(SAMPLE);
    } else {
      res.writeHead(404);
      res.end();
    }
  });
  await new Promise((r) => origin.listen(0, r));
  originBase = `http://127.0.0.1:${origin.address().port}`;
});

after(() => origin.close());

test("fetches a remote XML feed via request", async () => {
  const body = await fetchXml(`${originBase}/feed.xml`);
  assert.match(body, /<bookmarks>/);
});

test("parses bookmarks out of the XML", async () => {
  const items = await importBookmarks(SAMPLE);
  assert.equal(items.length, 2);
  assert.deepEqual(items[0], { title: "Docs", url: "https://docs.example.com" });
});

test("POST /import ingests an XML body", async () => {
